#include <stdio.h>

int main() {
    int t;
    scanf("%d", &t);
    while(t--) {
        int n;
        scanf("%d", &n);
        int arr[n];
        for(int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }

        // Find the maximum value in the array
        int max_element = arr[0];
        for(int i = 1; i < n; i++) {
            if(arr[i] > max_element) {
                max_element = arr[i];
            }
        }

        // Create and initialize the hash array
        int hash[max_element + 1];
        for(int i = 0; i <= max_element; i++) {
            hash[i] = 0;
        }

        // Count frequencies
        for(int i = 0; i < n; i++) {
            hash[arr[i]]++;
        }
        for(int i = 0; i < n; i++) {
            printf("%d ", hash[arr[i]]);
        }
        printf("\n");
    }
    return 0;
}

