import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef
{
    public static void main (String[] args) throws java.lang.Exception
    {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();

        while (t-- > 0) {
            int n = sc.nextInt();
            int[] arr = new int[n];
            int max_element = 0;

            // Read array and find maximum element
            for (int i = 0; i < n; i++) {
                arr[i] = sc.nextInt();
                if (arr[i] > max_element) {
                    max_element = arr[i];
                }
            }

            // Create and initialize the hash array
            int[] hash = new int[max_element + 1];
            for (int i = 0; i <= max_element; i++) {
                hash[i] = 0;
            }

            // Count frequencies
            for (int i = 0; i < n; i++) {
                hash[arr[i]]++;
            }

            // Print frequencies
            for (int i = 0; i < n; i++) {
                System.out.print(hash[arr[i]] + " ");
            }
            System.out.println();
        }
        sc.close();
    }
}

