const readline = require('readline');

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

function freqHash(input) {
    const lines = input.trim().split('\n');
    let index = 0;
    let T = parseInt(lines[index++], 10);

    let results = [];

    while (T--) {
        const n = parseInt(lines[index++], 10); 
        const arr = lines[index++].split(' ').map(Number);

        // Find the maximum value in the array
        const max_element = Math.max(...arr);

        // Create and initialize the hash array
        const hash = new Array(max_element + 1).fill(0);

        // Count frequencies
        arr.forEach(num => {
            hash[num]++;
        });

        // Collect result for the current test case
        const frequency = arr.map(num => hash[num]).join(' ');
        results.push(frequency);
    }
    console.log(results.join('\n'));
}

function main() {
    let input = '';

    rl.on('line', (line) => {
        input += line + '\n'; // Collect input lines
    });

    rl.on('close', () => {
        freqHash(input); // Process the collected input
    });
}

main();
